import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as p,f as e,a as n,b as s,e as o}from"./app-cd06214a.js";const i={},l=n("p",null,"자바스크립트는 함수를 호출하면 실행 컨텍스트 스택에 푸시되고 순차적으로 함수 코드가 실행된다.",-1),c=n("figure",null,[n("img",{src:"https://github.com/Zamoca42/blog/assets/96982072/fa7ba17d-3430-4ecd-9858-118ddadd6453",alt:"그림 42-1. 실행 컨텍스트 스택",tabindex:"0",loading:"lazy"}),n("figcaption",null,"그림 42-1. 실행 컨텍스트 스택")],-1),u=n("p",null,[s("자바스크립트 엔진은 한 번에 하나의 태스크만 실행할 수 있는 싱글 스레드 방식으로 동작하기 때문에"),n("br"),s(" 처리에 시간이 걸리는 태스크를 실행하는 경우 블로킹이 발생한다.")],-1),d=o(`<p>예를 들어, setTimeout 함수와 유사하게 일정 시간이 경과한 이후에 콜백 함수를 호출하는 sleep함수를 구현해 보자.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// sleep 함수는 일정 시간(delay)이 경과한 이후에 콜백 함수(func)를 호출한다.</span>
<span class="token keyword">function</span> <span class="token function">sleep</span><span class="token punctuation">(</span><span class="token parameter">func<span class="token punctuation">,</span> delay</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// Date.now()는 현재 시간을 숫자(ms)로 반환한다.(&quot;30.2.1. Date.now&quot; 참고)</span>
  <span class="token keyword">const</span> delayUntil <span class="token operator">=</span> Date<span class="token punctuation">.</span><span class="token function">now</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> delay<span class="token punctuation">;</span>

  <span class="token comment">// 현재 시간(Date.now())에 delay를 더한 delayUntil이 현재 시간보다 작으면 계속 반복한다.</span>
  <span class="token keyword">while</span> <span class="token punctuation">(</span>Date<span class="token punctuation">.</span><span class="token function">now</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&lt;</span> delayUntil<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token comment">// 일정 시간(delay)이 경과한 이후에 콜백 함수(func)를 호출한다.</span>
  <span class="token function">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;foo&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;bar&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// sleep 함수는 3초 이상 실행된다..</span>
<span class="token function">sleep</span><span class="token punctuation">(</span>foo<span class="token punctuation">,</span> <span class="token number">3</span> <span class="token operator">*</span> <span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// bar 함수는 sleep 함수의 실행이 종료된 이후에 호출되므로 3초 이상 블로킹된다.</span>
<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// (3초 경과 후) foo 호출 -&gt; bar 호출</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제의 sleep 함수는 3초 후에 foo 함수를 호출한다.</p><p>이때 bar 함수는 sleep 함수의 실행이 종료된 이후 호출되므로 3초 이상 호출되지 못하고 블로킹 된다.</p><p>이처럼 현재 실행 중인 태스크가 종료될 때까지 다음 태스크가 대기하는 방식을 <strong>동기 처리</strong>라고한다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/5036748d-36e5-4e48-8f57-d3e5f3ea2ced" alt="그림 42-2. 동기 처리" tabindex="0" loading="lazy"><figcaption>그림 42-2. 동기 처리</figcaption></figure><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;foo&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;bar&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 타이머 함수 setTimeout은 일정 시간이 경과한 이후에 콜백 함수 foo를 호출한다.</span>
<span class="token comment">// 타이머 함수 setTimeout은 bar 함수를 블로킹하지 않는다.</span>
<span class="token function">setTimeout</span><span class="token punctuation">(</span>foo<span class="token punctuation">,</span> <span class="token number">3</span> <span class="token operator">*</span> <span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// bar 호출 -&gt; (3초 경과 후) foo 호출</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>setTimeout 함수는 앞서 살펴본 sleep 함수와 유사하게 일정 시간이 경과한 이후에 콜백 함수를 호출하지만</p><p>setTimeout 함수 이후의 태스크를 블로킹하지 않고 곧바로 실행한다.</p><p>이처럼 현재 실행 중인 태스크가 종료되지 않은 상태라 해도 다음 태스크를 곧바로 실행하는 방식을 비동기 처리라고 한다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/3aa3b615-dcea-4998-ad94-3040ab32bd20" alt="그림 42-3. 비동기 처리" tabindex="0" loading="lazy"><figcaption>그림 42-3. 비동기 처리</figcaption></figure><h3 id="동기-처리-방식" tabindex="-1"><a class="header-anchor" href="#동기-처리-방식" aria-hidden="true">#</a> 동기 처리 방식</h3><ul><li>태스크를 순서대로 처리하므로 실행 순서가 보장된다는 장점</li><li>앞선 태스크가 종료할 때까지 이후 태스크들이 블로킹 되는 단점</li></ul><h3 id="비동기-처리-방식" tabindex="-1"><a class="header-anchor" href="#비동기-처리-방식" aria-hidden="true">#</a> 비동기 처리 방식</h3><ul><li>앞선 태스크가 종료할 때 까지 다음 태스크들이 블로킹이 발생하지 않음</li><li>태스크의 실행 순서가 보장되지 않는 단점</li><li>콜백 패턴을 사용 <ul><li>콜백 헬을 발생 시켜 가독성을 나쁘게함</li></ul></li><li>비동기 처리 중 발생한 에러의 예외 처리 곤란</li></ul><p>비동기 처리는 이벤트 루프와 태스크 큐와 깊은 관계가 있다.</p><h2 id="_2-이벤트-루프와-태스크-큐" tabindex="-1"><a class="header-anchor" href="#_2-이벤트-루프와-태스크-큐" aria-hidden="true">#</a> 2. 이벤트 루프와 태스크 큐</h2><p>자바스크립트는 싱글 스레드 방식으로 한번에 하나의 태스크만 처리할 수 있다는 것을 의미한다.<br> 하지만 브라우저가 동작하는 것을 살펴보면 많은 태스크가 동시에 처리되는 것처럼 느껴진다.</p><p>예를 들어, HTML 요소가 애니메이션 효과를 통해 움직이면서 이벤트를 처리하기도 하고,<br> HTTP 요청을 통해 서버로부터 데이터를 가지고 오면서 렌더링하기도 한다.</p><p>이처럼 자바스크립트의 동시성을 지원하는 것이 바로 이벤트 루프다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/c3f66c1f-1e48-4f2d-a472-62dad21de3cc" alt="그림 42-4. 이벤트 루프와 브라우저 환경" tabindex="0" loading="lazy"><figcaption>그림 42-4. 이벤트 루프와 브라우저 환경</figcaption></figure><p>구글의 V8 자바스크립트 엔진을 비롯한 대부분의 자바스크립트 엔진은 크게 2개의 영역으로 구분할 수 있다.</p><ul><li><p><strong>콜 스택(call stack)</strong></p><ul><li>실행 컨텍스트 스택이 바로 콜 스택이다.</li><li>함수를 호출하면 콜 스택에 푸시되어 순차적으로 실행된다.</li><li>최상위 실행 컨텍스트가 종료되어 콜 스택에서 제거되기 전까지는 어떤 태스크도 실행되지 않는다.</li></ul></li><li><p><strong>힙(heap)</strong></p><ul><li>힙은 객체가 저장되는 메모리 공간이다. 콜 스택의 요소인 실행 컨텍스트는 힙에 저장된 객체를 참조한다.</li><li>메모리에 값을 저장하려면 저장할 메모리 공간의 크기를 결정해야한다. <ul><li>객체는 크기가 정해져 있지않아 동적으로 할당해야 한다.</li><li>객체가 저장되는 메모리 공간인 힙은 구조화 되어있지 않다는 특징이 있다.</li></ul></li></ul></li></ul><p>비동기 처리에서 소스코드 평가와 실행을 제외한 모든 처리는 자바스크립트 엔진을 구동하는 환경인 브라우저 또는 Node.js가 담당한다.<br> 이를 위해 브라우저 환경은 태스크 큐와 이벤트 루프를 제공한다.</p><ul><li><p><strong>태스크 큐 (task queue/event queue/callback queue)</strong></p><ul><li>setTimeout이나 setInterval과 같은 비동기 함수의 콜백 함수 또는 이벤트 핸들러가 일시적으로 보관되는 영역이다.</li><li>태스크 큐와는 별도로 프로미스의 후속 처리 메서드의 콜백 함수가 일시적으로 보관되는 마이크로태스크 큐도 존재한다.</li></ul></li><li><p><strong>이벤트 루프 (event loop)</strong></p><ul><li>콜 스택에 현재 실행 중인 실행 컨텍스트가 있는지, 그리고 태스크 큐에 대기 중인 함수가 있는지 반복해서 확인한다.</li><li>콜 스택이 비어 있고 태스크 큐에 대기 중인 함수가 있다면 이벤트 루프는 순차적으로 태스크 큐에 대기 중인 함수를 콜 스택으로 이동시킨다.</li></ul></li></ul><p>브라우저 환경에서 다음 예제가 어떻게 동작할지 살펴보자.<br> foo 함수와 bar 함수 중에서 먼저 실행될 함수는 무엇일까?</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;foo&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;bar&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">setTimeout</span><span class="token punctuation">(</span>foo<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 0초(실제는 4ms) 후에 foo 함수가 호출된다.</span>
<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li><p>전역 코드가 평가되어 전역 실행 컨텍스트가 생성되고 콜 스택 푸시된다.</p></li><li><p>전역 코드가 실행되기 시작하여 setTimeout 함수가 호출된다.<br> 브라우저 Web API인 타이머 함수도 함수이므로 함수 실행 컨텍스트를 생성한다.</p></li><li><p>setTimeout 함수가 실행되면 콜백 함수를 호출 스케줄링하고 종료되어 콜 스택에서 팝된다.<br> 이때 호출 스케줄링, 즉 타이머 설정과 타이머가 만료되면 콜백 함수를 태스크 큐에 푸시하는 것은 브라우저의 역할이다.</p></li><li><p>브라우저 수행하는 1과 자바스크립트 엔진이 수행하는 2는 병행 처리된다.</p><ol><li><p>브라우저는 타이머를 설정하고 콜백 함수 foo가 태스크 큐에 푸시되어 대기하게 된다.</p></li><li><p>bar 함수가 호출되어 bar 함수의 함수 실행 컨텍스트가 생성된다.<br> 타이머 설정 시간 중이라면 foo 함수는 아직 태스크 큐에서 대기중이다.</p></li></ol></li><li><p>전역 코드 실행이 종료되고 전역 실행 컨텍스트가 콜 스택에서 팝된다.<br> 이로서 콜 스택에는 아무런 실행 컨텍스트도 존재하지 않게 된다.</p></li><li><p>이벤트 루프에 의해 콜 스택이 비어 있음이 감지되고 foo가 콜 스택에 푸시된다.</p></li></ol>`,28);function r(k,m){return t(),p("div",null,[l,c,u,e("more"),d])}const f=a(i,[["render",r],["__file","deepdive42.html.vue"]]);export{f as default};
